import { normalizeTagNames } from "@/features/tags/normalize";
import { serverLogger } from "@/lib/logging/server-logger";

export type MinaChatMessage = {
  role: "system" | "user";
  content: string;
};

export type EnrichmentMetadata = {
  summary: string;
  tags: string[];
};

type RequiredAiEnv = "LLM_BASE" | "TOKEN" | "MODEL";

type MinaAiConfig = {
  baseUrl: string;
  token: string;
  model: string;
};

export type MinaAiConfigStatus =
  | {
      state: "configured";
      config: MinaAiConfig;
    }
  | {
      state: "disabled";
    }
  | {
      state: "invalid";
      missing: RequiredAiEnv[];
    };

type MinaChatCompletionsResponse = {
  choices?: Array<{
    message?: {
      content?: string | Array<{ text?: string }>;
    };
  }>;
};

export class MinaAiClientError extends Error {
  constructor(
    readonly code: "disabled" | "invalid-config" | "bad-response" | "invalid-response",
    message: string
  ) {
    super(message);
    this.name = "MinaAiClientError";
  }
}

function readOptionalEnv(name: RequiredAiEnv) {
  const value = process.env[name]?.trim();

  return value ? value : null;
}

function normalizeBaseUrl(baseUrl: string) {
  return baseUrl.endsWith("/") ? baseUrl : `${baseUrl}/`;
}

function getMissingConfig(baseUrl: string | null, token: string | null, model: string | null) {
  const missing: RequiredAiEnv[] = [];

  if (!baseUrl) {
    missing.push("LLM_BASE");
  }

  if (!token) {
    missing.push("TOKEN");
  }

  if (!model) {
    missing.push("MODEL");
  }

  return missing;
}

function readMessageContent(content: MinaChatCompletionsResponse["choices"]) {
  const messageContent = content?.[0]?.message?.content;

  if (typeof messageContent === "string") {
    return messageContent;
  }

  if (Array.isArray(messageContent)) {
    return messageContent
      .map((part) => (typeof part.text === "string" ? part.text : ""))
      .join("")
      .trim();
  }

  return "";
}

export function getMinaAiConfigStatus(): MinaAiConfigStatus {
  const baseUrl = readOptionalEnv("LLM_BASE");
  const token = readOptionalEnv("TOKEN");
  const model = readOptionalEnv("MODEL");
  const missing = getMissingConfig(baseUrl, token, model);

  if (missing.length === 3) {
    return {
      state: "disabled"
    };
  }

  if (missing.length > 0) {
    return {
      state: "invalid",
      missing
    };
  }

  return {
    state: "configured",
    config: {
      baseUrl: baseUrl ?? "",
      token: token ?? "",
      model: model ?? ""
    }
  };
}

export function buildMinaChatCompletionsRequest(messages: MinaChatMessage[]) {
  const configStatus = getMinaAiConfigStatus();

  if (configStatus.state === "disabled") {
    throw new MinaAiClientError("disabled", "LLM_BASE, TOKEN, and MODEL must be set before AI enrichment can run.");
  }

  if (configStatus.state === "invalid") {
    throw new MinaAiClientError(
      "invalid-config",
      `AI enrichment configuration is incomplete. Missing: ${configStatus.missing.join(", ")}.`
    );
  }

  return {
    endpoint: new URL("chat/completions", normalizeBaseUrl(configStatus.config.baseUrl)).toString(),
    init: {
      method: "POST",
      headers: {
        Authorization: `Bearer ${configStatus.config.token}`,
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        model: configStatus.config.model,
        messages,
        response_format: {
          type: "json_object"
        }
      })
    }
  };
}

export function normalizeMinaEnrichmentResponse(payload: unknown): EnrichmentMetadata {
  const rawContent = readMessageContent((payload as MinaChatCompletionsResponse | null)?.choices);

  if (!rawContent) {
    throw new MinaAiClientError("bad-response", "The Mina AI endpoint returned no completion content.");
  }

  let parsed: unknown;

  try {
    parsed = JSON.parse(rawContent);
  } catch {
    throw new MinaAiClientError("invalid-response", "The Mina AI endpoint returned non-JSON enrichment content.");
  }

  const summary = typeof (parsed as { summary?: unknown }).summary === "string" ? (parsed as { summary: string }).summary.trim() : "";
  const rawTags = Array.isArray((parsed as { tags?: unknown }).tags) ? (parsed as { tags: unknown[] }).tags : null;

  if (!summary || !rawTags) {
    throw new MinaAiClientError("invalid-response", "The Mina AI endpoint omitted the normalized summary or tags fields.");
  }

  return {
    summary,
    tags: normalizeTagNames(
      rawTags
        .map((tag) => (typeof tag === "string" ? tag : ""))
        .filter(Boolean)
        .join(",")
    )
  };
}

export async function requestMinaEnrichment(messages: MinaChatMessage[]) {
  const request = buildMinaChatCompletionsRequest(messages);
  const response = await fetch(request.endpoint, request.init);

  if (!response.ok) {
    serverLogger.warn("Mina AI request failed.", {
      status: response.status,
      statusText: response.statusText
    });
    throw new MinaAiClientError("bad-response", `The Mina AI endpoint returned HTTP ${response.status}.`);
  }

  return normalizeMinaEnrichmentResponse(await response.json());
}

function requireEnv(name: string) {
  const value = process.env[name];

  if (!value) {
    throw new Error(`Missing required environment variable: ${name}`);
  }

  return value;
}

export const env = {
  authSecret: requireEnv("AUTH_SECRET"),
  databaseUrl: requireEnv("DATABASE_URL"),
  ownerUsername: requireEnv("OWNER_USERNAME"),
  ownerPassword: requireEnv("OWNER_PASSWORD"),
  logLevel: process.env.LOG_LEVEL ?? "info"
};

import { type MinaAiConfigStatus, MinaAiClientError, getMinaAiConfigStatus } from "@/features/ai/client";

type EnrichmentStateWriter<TRecord> = {
  setEnrichmentPending(id: string): Promise<TRecord>;
  setEnrichmentReady(id: string): Promise<TRecord>;
  setEnrichmentFailed(id: string, error: string): Promise<TRecord>;
};

function getConfigurationFailureMessage(configStatus: MinaAiConfigStatus) {
  if (configStatus.state === "disabled") {
    return "Set LLM_BASE, TOKEN, and MODEL before AI enrichment can run.";
  }

  if (configStatus.state === "invalid") {
    return `Complete the AI enrichment configuration. Missing: ${configStatus.missing.join(", ")}.`;
  }

  return "AI enrichment failed.";
}

export function normalizeEnrichmentFailure(error: unknown) {
  if (error instanceof MinaAiClientError) {
    return error.message;
  }

  if (error instanceof Error && error.message.trim()) {
    return error.message.trim().slice(0, 240);
  }

  return "AI enrichment failed.";
}

export async function requestEnrichment<TRecord>(writer: EnrichmentStateWriter<TRecord>, id: string) {
  const configStatus = getMinaAiConfigStatus();

  if (configStatus.state === "configured") {
    return writer.setEnrichmentPending(id);
  }

  return writer.setEnrichmentFailed(id, getConfigurationFailureMessage(configStatus));
}

export async function retryEnrichment<TRecord>(writer: EnrichmentStateWriter<TRecord>, id: string) {
  return requestEnrichment(writer, id);
}

export async function completeEnrichment<TRecord>(writer: EnrichmentStateWriter<TRecord>, id: string) {
  return writer.setEnrichmentReady(id);
}

export async function failEnrichment<TRecord>(writer: EnrichmentStateWriter<TRecord>, id: string, error: unknown) {
  return writer.setEnrichmentFailed(id, normalizeEnrichmentFailure(error));
}

import "server-only";

import { requestEnrichment, retryEnrichment } from "@/features/enrichment/service";
import { notesRepo } from "@/features/notes/repo";
import { createNoteExcerpt } from "@/features/notes/markdown";
import type { NoteDraftInput } from "@/features/notes/types";
import { createUniqueNoteSlug } from "@/features/notes/slug";
import { normalizeTagNames } from "@/features/tags/normalize";

function normalizeTitle(title: string) {
  const trimmedTitle = title.trim();

  return trimmedTitle || "Untitled note";
}

export async function listOwnerNotes(ownerId: string) {
  return notesRepo.listForOwner(ownerId);
}

export async function listPublishedNotes() {
  const notes = await notesRepo.listPublished();

  return notes.filter((note): note is typeof note & { publishedAt: Date } => note.publishedAt !== null);
}

export async function getOwnerNoteForEditor(ownerId: string, id: string) {
  return notesRepo.findByIdForOwner(ownerId, id);
}

export async function getPublishedNoteBySlug(slug: string) {
  const note = await notesRepo.findPublishedBySlug(slug);

  if (!note?.publishedAt) {
    return null;
  }

  return note;
}

export async function createDraftNote(ownerId: string, input: NoteDraftInput) {
  const title = normalizeTitle(input.title);
  const markdown = input.markdown;
  const tagNames = normalizeTagNames(input.tags);
  const existingSlugs = await notesRepo.listSlugsForOwner(ownerId);
  const note = await notesRepo.create(ownerId, {
    title,
    slug: createUniqueNoteSlug(title, existingSlugs),
    markdown,
    excerpt: createNoteExcerpt(markdown, title),
    tagNames
  });

  await requestEnrichment(notesRepo, note.id);

  return note;
}

export async function updateDraftNote(ownerId: string, id: string, input: NoteDraftInput) {
  const existingNote = await notesRepo.findByIdForOwner(ownerId, id);

  if (!existingNote) {
    return null;
  }

  const title = normalizeTitle(input.title);
  const markdown = input.markdown;
  const tagNames = normalizeTagNames(input.tags);
  const existingSlugs = await notesRepo.listSlugsForOwner(ownerId);
  const siblingSlugs = existingSlugs.filter((slug) => slug !== existingNote.slug);
  const note = await notesRepo.update(id, {
    title,
    slug: createUniqueNoteSlug(title, siblingSlugs),
    markdown,
    excerpt: createNoteExcerpt(markdown, title),
    tagNames
  });

  await requestEnrichment(notesRepo, note.id);

  return note;
}

export async function publishNote(ownerId: string, id: string) {
  const existingNote = await notesRepo.findByIdForOwner(ownerId, id);

  if (!existingNote) {
    return null;
  }

  if (existingNote.isPublished) {
    return existingNote;
  }

  return notesRepo.updatePublication(id, true);
}

export async function unpublishNote(ownerId: string, id: string) {
  const existingNote = await notesRepo.findByIdForOwner(ownerId, id);

  if (!existingNote) {
    return null;
  }

  if (!existingNote.isPublished) {
    return existingNote;
  }

  return notesRepo.updatePublication(id, false);
}

export async function retryNoteEnrichment(ownerId: string, id: string) {
  const note = await notesRepo.findByIdForOwner(ownerId, id);

  if (!note) {
    return null;
  }

  return retryEnrichment(notesRepo, id);
}

import "server-only";

import { Prisma } from "@prisma/client";

import { requestEnrichment, retryEnrichment } from "@/features/enrichment/service";
import { normalizeLinkInput } from "@/features/links/normalize";
import { linksRepo } from "@/features/links/repo";
import type { LinkDraftInput } from "@/features/links/types";

export class DuplicateLinkUrlError extends Error {
  constructor() {
    super("duplicate-link-url");
    this.name = "DuplicateLinkUrlError";
  }
}

export async function listOwnerLinks(ownerId: string) {
  return linksRepo.listForOwner(ownerId);
}

export async function createSavedLink(ownerId: string, input: LinkDraftInput) {
  const normalizedInput = normalizeLinkInput(input);

  try {
    const link = await linksRepo.create(ownerId, normalizedInput);

    await requestEnrichment(linksRepo, link.id);

    return link;
  } catch (error) {
    if (error instanceof Prisma.PrismaClientKnownRequestError && error.code === "P2002") {
      throw new DuplicateLinkUrlError();
    }

    throw error;
  }
}

export async function retryLinkEnrichment(ownerId: string, id: string) {
  const link = await linksRepo.findByIdForOwner(ownerId, id);

  if (!link) {
    return null;
  }

  return retryEnrichment(linksRepo, id);
}

export const ENRICHMENT_STATUSES = ["pending", "ready", "failed"] as const;

export type EnrichmentStatus = (typeof ENRICHMENT_STATUSES)[number];

export type EnrichmentState = {
  status: EnrichmentStatus;
  error: string | null;
  attempts: number;
  updatedAt: Date | null;
};

export type EnrichmentRecordFields = {
  enrichmentStatus: string;
  enrichmentError: string | null;
  enrichmentAttempts: number;
  enrichmentUpdatedAt: Date | null;
};

export function normalizeEnrichmentStatus(status: string): EnrichmentStatus {
  if (ENRICHMENT_STATUSES.includes(status as EnrichmentStatus)) {
    return status as EnrichmentStatus;
  }

  return "failed";
}

export function toEnrichmentState(record: EnrichmentRecordFields): EnrichmentState {
  return {
    status: normalizeEnrichmentStatus(record.enrichmentStatus),
    error: record.enrichmentError,
    attempts: record.enrichmentAttempts,
    updatedAt: record.enrichmentUpdatedAt
  };
}

export function getEnrichmentStatusLabel(status: EnrichmentStatus) {
  switch (status) {
    case "pending":
      return "AI pending";
    case "ready":
      return "AI ready";
    case "failed":
      return "AI failed";
  }
}

export function getEnrichmentStatusDetail(state: EnrichmentState) {
  if (state.status === "failed") {
    return state.error ?? "AI enrichment failed.";
  }

  if (state.status === "ready") {
    return "Generated metadata is ready for later note and link surfaces.";
  }

  return "A save has queued enrichment for the configured Mina endpoint.";
}

import "dotenv/config";

export const AI_REAL_TEST_TAG = "@ai-real";
export const AI_REAL_ENV_MESSAGE = "Requires LLM_BASE, TOKEN, and MODEL.";

export function hasAiRealEnv() {
  return Boolean(process.env.LLM_BASE?.trim() && process.env.TOKEN?.trim() && process.env.MODEL?.trim());
}

import "server-only";

import type { EnrichmentRecordFields } from "@/features/enrichment/types";
import { toEnrichmentState } from "@/features/enrichment/types";
import { prisma } from "@/lib/prisma";

const linkTagSelect = {
  orderBy: {
    name: "asc" as const
  },
  select: {
    id: true,
    name: true
  }
};

const linkSummarySelect = {
  id: true,
  url: true,
  title: true,
  summary: true,
  enrichmentStatus: true,
  enrichmentError: true,
  enrichmentAttempts: true,
  enrichmentUpdatedAt: true,
  createdAt: true,
  updatedAt: true,
  tags: linkTagSelect
};

function mapLinkRecord<TRecord extends EnrichmentRecordFields>(link: TRecord) {
  const { enrichmentStatus, enrichmentError, enrichmentAttempts, enrichmentUpdatedAt, ...rest } = link;

  return {
    ...rest,
    enrichment: toEnrichmentState({
      enrichmentStatus,
      enrichmentError,
      enrichmentAttempts,
      enrichmentUpdatedAt
    })
  };
}

export const linksRepo = {
  async listForOwner(ownerId: string) {
    const links = await prisma.link.findMany({
      where: {
        ownerId
      },
      orderBy: {
        updatedAt: "desc"
      },
      select: linkSummarySelect
    });

    return links.map(mapLinkRecord);
  },
  async listForOwnerByTag(ownerId: string, tagName: string) {
    const links = await prisma.link.findMany({
      where: {
        ownerId,
        tags: {
          some: {
            name: tagName
          }
        }
      },
      orderBy: {
        updatedAt: "desc"
      },
      select: linkSummarySelect
    });

    return links.map(mapLinkRecord);
  },
  async findByIdForOwner(ownerId: string, id: string) {
    const link = await prisma.link.findFirst({
      where: {
        id,
        ownerId
      },
      select: linkSummarySelect
    });

    return link ? mapLinkRecord(link) : null;
  },
  async searchForOwner(ownerId: string, query: string) {
    const links = await prisma.link.findMany({
      where: {
        ownerId,
        OR: [
          {
            title: {
              contains: query
            }
          },
          {
            url: {
              contains: query
            }
          },
          {
            tags: {
              some: {
                name: {
                  contains: query
                }
              }
            }
          }
        ]
      },
      orderBy: {
        updatedAt: "desc"
      },
      select: linkSummarySelect
    });

    return links.map(mapLinkRecord);
  },
  async create(ownerId: string, data: { url: string; title: string; summary: string; tagNames: string[] }) {
    const link = await prisma.link.create({
      data: {
        ownerId,
        url: data.url,
        title: data.title,
        summary: data.summary,
        tags: {
          connectOrCreate: data.tagNames.map((name) => ({
            where: {
              name
            },
            create: {
              name
            }
          }))
        }
      },
      select: linkSummarySelect
    });

    return mapLinkRecord(link);
  },
  async setEnrichmentPending(id: string) {
    const link = await prisma.link.update({
      where: {
        id
      },
      data: {
        enrichmentStatus: "pending",
        enrichmentError: null,
        enrichmentAttempts: {
          increment: 1
        },
        enrichmentUpdatedAt: new Date()
      },
      select: linkSummarySelect
    });

    return mapLinkRecord(link);
  },
  async setEnrichmentReady(id: string) {
    const link = await prisma.link.update({
      where: {
        id
      },
      data: {
        enrichmentStatus: "ready",
        enrichmentError: null,
        enrichmentUpdatedAt: new Date()
      },
      select: linkSummarySelect
    });

    return mapLinkRecord(link);
  },
  async setEnrichmentFailed(id: string, error: string) {
    const link = await prisma.link.update({
      where: {
        id
      },
      data: {
        enrichmentStatus: "failed",
        enrichmentError: error,
        enrichmentAttempts: {
          increment: 1
        },
        enrichmentUpdatedAt: new Date()
      },
      select: linkSummarySelect
    });

    return mapLinkRecord(link);
  }
};

