  const resolvedSearchParams = (await searchParams) ?? {};
  const links = await listOwnerLinks(owner.id);
  const statusMessage =
    resolvedSearchParams.saved === "1" ? "Link saved." : getStatusMessage(resolvedSearchParams.error);

  return (
    <div className="feature-layout">
      <section className="feature-card">
        <p className="eyebrow">Private links</p>
        <h1>Save links for later retrieval.</h1>
        <p className="lede">
          Manual bookmark capture stays private in v1. Each saved link keeps its URL, title, summary, and shared tags
          inside the owner area only.
        </p>
        {statusMessage ? (
          <p className={resolvedSearchParams.error ? "status-note status-note-error" : "status-note"}>{statusMessage}</p>
        ) : null}
      </section>

      <div className="link-manager-grid">
        <form action={createLinkAction} className="panel-card link-form">
          <strong>Capture a link</strong>
          <label className="field-group">
            <span>URL</span>
            <input
              autoComplete="url"
              className="text-input"
              name="url"
              placeholder="https://example.com/article"
              required
              type="url"
            />
          </label>
          <label className="field-group">
            <span>Title</span>
            <input
              autoComplete="off"
              className="text-input"
              name="title"
              placeholder="Reference title"
              required
              type="text"
            />
          </label>
          <label className="field-group">
            <span>Summary</span>
            <textarea
              className="note-textarea summary-textarea"
              name="summary"
              placeholder="Why this link matters and what you expect to find there later."
              required
            />
          </label>
          <label className="field-group">
            <span>Tags</span>
            <input
              autoComplete="off"
              className="text-input"
              name="tags"
              placeholder="research, reference"
              type="text"
            />
          </label>
          <p className="field-note">Use commas to share tags with the rest of the private vault.</p>
          <div className="button-row">
            <button className="primary-button" type="submit">
              Save link
            </button>
          </div>
        </form>

        <section className="panel-card link-list-panel">
          <strong>Saved links</strong>
          {links.length === 0 ? (
            <p>No saved links yet. Capture the first private bookmark from this page.</p>
          ) : (
            <div className="link-list">
              {links.map((link) => (
                <article className="link-list-item" key={link.id}>
                  <div className="link-list-heading">
                    <a className="note-list-link" href={link.url} rel="noopener noreferrer" target="_blank">
                      {link.title}
                    </a>
                    <p className="link-url">{link.url}</p>
                  </div>
                  <p className="link-summary">{link.summary}</p>
                  <div className="link-list-footer">
                    <div className="tag-list" aria-label="Tags">
                      {link.tags.length === 0 ? (
                        <span className="tag-pill tag-pill-muted">Untagged</span>
                      ) : (
                        link.tags.map((tag) => (
                          <span className="tag-pill" key={tag.id}>
                            {tag.name}
                          </span>
                        ))
                      )}
                    </div>
                    <div className="note-meta">
                      <span>Private link</span>
                      <span>{getEnrichmentStatusLabel(link.enrichment.status)}</span>
                      <span>{new Intl.DateTimeFormat("en", { dateStyle: "medium" }).format(link.updatedAt)}</span>
                    </div>
                  </div>
                  {link.enrichment.status === "failed" ? <p className="field-note">{getEnrichmentStatusDetail(link.enrichment)}</p> : null}
                </article>
              ))}
            </div>
          )}
        </section>
      </div>
    </div>
  );
}

"use server";

import { redirect } from "next/navigation";
import { revalidatePath } from "next/cache";

import { LinkValidationError } from "@/features/links/normalize";
import { DuplicateLinkUrlError, createSavedLink } from "@/features/links/service";
import { requireOwnerSession } from "@/lib/auth/owner-session";

function getLinkInput(formData: FormData) {
  return {
    url: String(formData.get("url") ?? ""),
    title: String(formData.get("title") ?? ""),
    summary: String(formData.get("summary") ?? ""),
    tags: String(formData.get("tags") ?? "")
  };
}

export async function createLinkAction(formData: FormData) {
  const owner = await requireOwnerSession();

  try {
    await createSavedLink(owner.id, getLinkInput(formData));
  } catch (error) {
    if (error instanceof LinkValidationError) {
      redirect(`/app/links?error=${error.code}`);
    }

    if (error instanceof DuplicateLinkUrlError) {
      redirect("/app/links?error=duplicate-url");
    }

    throw error;
  }

  revalidatePath("/app/links");
  revalidatePath("/app/search");
  revalidatePath("/app/tags");
  redirect("/app/links?saved=1");
}

import "server-only";

export const MINA_AI_ENV_KEYS = ["LLM_BASE", "TOKEN", "MODEL"] as const;

export type RequiredAiEnv = (typeof MINA_AI_ENV_KEYS)[number];

type MinaAiConfig = {
  baseUrl: string;
  token: string;
  model: string;
};

export type MinaAiConfigStatus =
  | {
      state: "configured";
      config: MinaAiConfig;
    }
  | {
      state: "disabled";
    }
  | {
      state: "invalid";
      missing: RequiredAiEnv[];
    };

function readOptionalEnv(name: RequiredAiEnv) {
  const value = process.env[name]?.trim();

  return value ? value : null;
}

function getMissingConfig(baseUrl: string | null, token: string | null, model: string | null) {
  const missing: RequiredAiEnv[] = [];

  if (!baseUrl) {
    missing.push("LLM_BASE");
  }

  if (!token) {
    missing.push("TOKEN");
  }

  if (!model) {
    missing.push("MODEL");
  }

  return missing;
}

export function getMinaAiConfigStatus(): MinaAiConfigStatus {
  const baseUrl = readOptionalEnv("LLM_BASE");
  const token = readOptionalEnv("TOKEN");
  const model = readOptionalEnv("MODEL");
  const missing = getMissingConfig(baseUrl, token, model);

  if (missing.length === MINA_AI_ENV_KEYS.length) {
    return {
      state: "disabled"
    };
  }

  if (missing.length > 0) {
    return {
      state: "invalid",
      missing
    };
  }

  return {
    state: "configured",
    config: {
      baseUrl: baseUrl ?? "",
      token: token ?? "",
      model: model ?? ""
    }
  };
}

import "server-only";

import { type MinaAiConfigStatus, getMinaAiConfigStatus } from "@/features/ai/config";
import { MinaAiClientError } from "@/features/ai/client";

type EnrichmentStateWriter<TRecord> = {
  setEnrichmentPending(id: string): Promise<TRecord>;
  setEnrichmentReady(id: string): Promise<TRecord>;
  setEnrichmentFailed(id: string, error: string): Promise<TRecord>;
};

function getConfigurationFailureMessage(configStatus: MinaAiConfigStatus) {
  if (configStatus.state === "disabled") {
    return "Set LLM_BASE, TOKEN, and MODEL before AI enrichment can run.";
  }

  if (configStatus.state === "invalid") {
    return `Complete the AI enrichment configuration. Missing: ${configStatus.missing.join(", ")}.`;
  }

  return "AI enrichment failed.";
}

export function normalizeEnrichmentFailure(error: unknown) {
  if (error instanceof MinaAiClientError) {
    return error.message;
  }

  if (error instanceof Error && error.message.trim()) {
    return error.message.trim().slice(0, 240);
  }

  return "AI enrichment failed.";
}

export async function requestEnrichment<TRecord>(writer: EnrichmentStateWriter<TRecord>, id: string) {
  const configStatus = getMinaAiConfigStatus();

  if (configStatus.state === "configured") {
    return writer.setEnrichmentPending(id);
  }

  return writer.setEnrichmentFailed(id, getConfigurationFailureMessage(configStatus));
}

export async function retryEnrichment<TRecord>(writer: EnrichmentStateWriter<TRecord>, id: string) {
  return requestEnrichment(writer, id);
}

export async function completeEnrichment<TRecord>(writer: EnrichmentStateWriter<TRecord>, id: string) {
  return writer.setEnrichmentReady(id);
}

export async function failEnrichment<TRecord>(writer: EnrichmentStateWriter<TRecord>, id: string, error: unknown) {
  return writer.setEnrichmentFailed(id, normalizeEnrichmentFailure(error));
}

import test from "node:test";
import assert from "node:assert/strict";

import { getMinaAiConfigStatus } from "../../src/features/ai/config";
import {
  buildMinaChatCompletionsRequest,
  normalizeMinaEnrichmentResponse
} from "../../src/features/ai/client";

function withAiEnv(values: Partial<Record<"LLM_BASE" | "TOKEN" | "MODEL", string | undefined>>, callback: () => void) {
  const original = {
    LLM_BASE: process.env.LLM_BASE,
    TOKEN: process.env.TOKEN,
    MODEL: process.env.MODEL
  };

  if (values.LLM_BASE === undefined) {
    delete process.env.LLM_BASE;
  } else {
    process.env.LLM_BASE = values.LLM_BASE;
  }

  if (values.TOKEN === undefined) {
    delete process.env.TOKEN;
  } else {
    process.env.TOKEN = values.TOKEN;
  }

  if (values.MODEL === undefined) {
    delete process.env.MODEL;
  } else {
    process.env.MODEL = values.MODEL;
  }

  try {
    callback();
  } finally {
    if (original.LLM_BASE === undefined) {
      delete process.env.LLM_BASE;
    } else {
      process.env.LLM_BASE = original.LLM_BASE;
    }

    if (original.TOKEN === undefined) {
      delete process.env.TOKEN;
    } else {
      process.env.TOKEN = original.TOKEN;
    }

    if (original.MODEL === undefined) {
      delete process.env.MODEL;
    } else {
      process.env.MODEL = original.MODEL;
    }
  }
}

test("getMinaAiConfigStatus returns disabled when no AI env vars are set", () => {
  withAiEnv({ LLM_BASE: undefined, TOKEN: undefined, MODEL: undefined }, () => {
    assert.deepEqual(getMinaAiConfigStatus(), {
      state: "disabled"
    });
  });
});

test("buildMinaChatCompletionsRequest shapes the Mina OpenAI-compatible request", () => {
  withAiEnv(
    {
      LLM_BASE: "https://mina.example/v1",
      TOKEN: "test-token",
      MODEL: "mina-model"
    },
    () => {
      const request = buildMinaChatCompletionsRequest([
        {
          role: "system",
          content: "Return JSON."
        },
        {
          role: "user",
          content: "Summarize this note."
        }
      ]);

      assert.equal(request.endpoint, "https://mina.example/v1/chat/completions");
      assert.equal(request.init.method, "POST");
      assert.deepEqual(request.init.headers, {
        Authorization: "Bearer test-token",
        "Content-Type": "application/json"
      });
      assert.deepEqual(JSON.parse(request.init.body), {
        model: "mina-model",
        messages: [
          {
            role: "system",
            content: "Return JSON."
          },
          {
            role: "user",
            content: "Summarize this note."
          }
        ],
        response_format: {
          type: "json_object"
        }
      });
    }
  );
});

test("normalizeMinaEnrichmentResponse trims the summary and normalizes repeated tags", () => {
  const enrichment = normalizeMinaEnrichmentResponse({
    choices: [
      {
        message: {
          content: JSON.stringify({
            summary: " Helpful generated summary. ",
            tags: ["Docs", "docs", "Reference"]
          })
        }
      }
    ]
  });

  assert.deepEqual(enrichment, {
    summary: "Helpful generated summary.",
    tags: ["docs", "reference"]
  });
});

