export const AI_REAL_TEST_TAG = "@ai-real";
export const AI_REAL_ENV_KEYS = ["LLM_BASE", "TOKEN", "MODEL"] as const;
export const AI_REAL_ENV_MESSAGE = `Requires ${AI_REAL_ENV_KEYS.join(", ")}.`;

export function getAiRealEnvStatus() {
  const missing = AI_REAL_ENV_KEYS.filter((name) => !process.env[name]?.trim());

  return {
    configured: missing.length === 0,
    missing
  };
}

export function hasAiRealEnv() {
  return getAiRealEnvStatus().configured;
}

import "server-only";

import { normalizeTagNames } from "@/features/tags/normalize";
import { getMinaAiConfigStatus } from "@/features/ai/config";
import { serverLogger } from "@/lib/logging/server-logger";

export type MinaChatMessage = {
  role: "system" | "user";
  content: string;
};

export type EnrichmentMetadata = {
  summary: string;
  tags: string[];
};

type MinaChatCompletionsResponse = {
  choices?: Array<{
    message?: {
      content?: string | Array<{ text?: string }>;
    };
  }>;
};

export class MinaAiClientError extends Error {
  constructor(
    readonly code: "disabled" | "invalid-config" | "bad-response" | "invalid-response",
    message: string
  ) {
    super(message);
    this.name = "MinaAiClientError";
  }
}

function normalizeBaseUrl(baseUrl: string) {
  return baseUrl.endsWith("/") ? baseUrl : `${baseUrl}/`;
}

function readMessageContent(content: MinaChatCompletionsResponse["choices"]) {
  const messageContent = content?.[0]?.message?.content;

  if (typeof messageContent === "string") {
    return messageContent;
  }

  if (Array.isArray(messageContent)) {
    return messageContent
      .map((part) => (typeof part.text === "string" ? part.text : ""))
      .join("")
      .trim();
  }

  return "";
}

export function buildMinaChatCompletionsRequest(messages: MinaChatMessage[]) {
  const configStatus = getMinaAiConfigStatus();

  if (configStatus.state === "disabled") {
    throw new MinaAiClientError("disabled", "LLM_BASE, TOKEN, and MODEL must be set before AI enrichment can run.");
  }

  if (configStatus.state === "invalid") {
    throw new MinaAiClientError(
      "invalid-config",
      `AI enrichment configuration is incomplete. Missing: ${configStatus.missing.join(", ")}.`
    );
  }

  return {
    endpoint: new URL("chat/completions", normalizeBaseUrl(configStatus.config.baseUrl)).toString(),
    init: {
      method: "POST",
      headers: {
        Authorization: `Bearer ${configStatus.config.token}`,
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        model: configStatus.config.model,
        messages,
        response_format: {
          type: "json_object"
        }
      })
    }
  };
}

export function normalizeMinaEnrichmentResponse(payload: unknown): EnrichmentMetadata {
  const rawContent = readMessageContent((payload as MinaChatCompletionsResponse | null)?.choices);

  if (!rawContent) {
    throw new MinaAiClientError("bad-response", "The Mina AI endpoint returned no completion content.");
  }

  let parsed: unknown;

  try {
    parsed = JSON.parse(rawContent);
  } catch {
    throw new MinaAiClientError("invalid-response", "The Mina AI endpoint returned non-JSON enrichment content.");
  }

  const summary = typeof (parsed as { summary?: unknown }).summary === "string" ? (parsed as { summary: string }).summary.trim() : "";
  const rawTags = Array.isArray((parsed as { tags?: unknown }).tags) ? (parsed as { tags: unknown[] }).tags : null;

  if (!summary || !rawTags) {
    throw new MinaAiClientError("invalid-response", "The Mina AI endpoint omitted the normalized summary or tags fields.");
  }

  return {
    summary,
    tags: normalizeTagNames(
      rawTags
        .map((tag) => (typeof tag === "string" ? tag : ""))
        .filter(Boolean)
        .join(",")
    )
  };
}

export async function requestMinaEnrichment(messages: MinaChatMessage[]) {
  const request = buildMinaChatCompletionsRequest(messages);
  const response = await fetch(request.endpoint, request.init);

  if (!response.ok) {
    serverLogger.warn("Mina AI request failed.", {
      status: response.status,
      statusText: response.statusText
    });
    throw new MinaAiClientError("bad-response", `The Mina AI endpoint returned HTTP ${response.status}.`);
  }

  return normalizeMinaEnrichmentResponse(await response.json());
}

import test from "node:test";
import assert from "node:assert/strict";

import { requestEnrichment } from "../../src/features/enrichment/service";

function withAiEnv(values: Partial<Record<"LLM_BASE" | "TOKEN" | "MODEL", string | undefined>>, callback: () => Promise<void>) {
  const original = {
    LLM_BASE: process.env.LLM_BASE,
    TOKEN: process.env.TOKEN,
    MODEL: process.env.MODEL
  };

  if (values.LLM_BASE === undefined) {
    delete process.env.LLM_BASE;
  } else {
    process.env.LLM_BASE = values.LLM_BASE;
  }

  if (values.TOKEN === undefined) {
    delete process.env.TOKEN;
  } else {
    process.env.TOKEN = values.TOKEN;
  }

  if (values.MODEL === undefined) {
    delete process.env.MODEL;
  } else {
    process.env.MODEL = values.MODEL;
  }

  return callback().finally(() => {
    if (original.LLM_BASE === undefined) {
      delete process.env.LLM_BASE;
    } else {
      process.env.LLM_BASE = original.LLM_BASE;
    }

    if (original.TOKEN === undefined) {
      delete process.env.TOKEN;
    } else {
      process.env.TOKEN = original.TOKEN;
    }

    if (original.MODEL === undefined) {
      delete process.env.MODEL;
    } else {
      process.env.MODEL = original.MODEL;
    }
  });
}

test("requestEnrichment records a failed state when the AI env is not configured", async () => {
  const calls: string[] = [];

  await withAiEnv({ LLM_BASE: undefined, TOKEN: undefined, MODEL: undefined }, async () => {
    await requestEnrichment(
      {
        setEnrichmentPending: async () => {
          calls.push("pending");
          return "pending";
        },
        setEnrichmentReady: async () => "ready",
        setEnrichmentFailed: async (_id, error) => {
          calls.push(error);
          return "failed";
        }
      },
      "note-1"
    );
  });

  assert.deepEqual(calls, ["Set LLM_BASE, TOKEN, and MODEL before AI enrichment can run."]);
});

test("requestEnrichment records a pending state when the AI env is configured", async () => {
  const calls: string[] = [];

  await withAiEnv(
    {
      LLM_BASE: "https://mina.example/v1",
      TOKEN: "token",
      MODEL: "model"
    },
    async () => {
      await requestEnrichment(
        {
          setEnrichmentPending: async (id) => {
            calls.push(id);
            return "pending";
          },
          setEnrichmentReady: async () => "ready",
          setEnrichmentFailed: async (_id, error) => {
            calls.push(error);
            return "failed";
          }
        },
        "link-1"
      );
    }
  );

  assert.deepEqual(calls, ["link-1"]);
});

test("requestEnrichment records which AI env vars are missing when the Mina config is partial", async () => {
  const calls: string[] = [];

  await withAiEnv(
    {
      LLM_BASE: "https://mina.example/v1",
      TOKEN: "token",
      MODEL: undefined
    },
    async () => {
      await requestEnrichment(
        {
          setEnrichmentPending: async () => {
            calls.push("pending");
            return "pending";
          },
          setEnrichmentReady: async () => "ready",
          setEnrichmentFailed: async (_id, error) => {
            calls.push(error);
            return "failed";
          }
        },
        "note-2"
      );
    }
  );

  assert.deepEqual(calls, ["Complete the AI enrichment configuration. Missing: MODEL."]);
});

